module top_module(input clk, input reset, input [3:0] bin_in, output [3:0] gray_out);reg [3:0] invalid_gray;

    always @(posedge clk) begin
        if (reset)
            invalid_gray <= 4'b0000;
        else begin
            invalid_gray[3] <= bin_in[3];
            invalid_gray[2] <= bin_in[3] ^ bin_in[2];
            invalid_gray[1] <= bin_in[2] ^ bin_in[1];
            invalid_gray[0] <= bin_in[1] ^ bin_in[0];
        end
    end

    assign gray_out = invalid_gray;

endmodule
